// Validate & normalize the input payload.
const b = $input.first().json.body || $input.first().json;
const required = ['domain','target_keyword','client_id'];
for (const f of required) if (!b[f]) throw new Error(`Missing required field: ${f}`);
const normalized = {
  task_id: `seo_${Date.now()}_${Math.random().toString(36).slice(2,8)}`,
  domain: b.domain.replace(/^https?:\/\//, '').replace(/\/$/, ''),
  target_keyword: b.target_keyword,
  secondary_keywords: (b.secondary_keywords || []).slice(0, 20),
  locale: b.locale || { country: 'US', language: 'en' },
  competitors: (b.competitors || []).slice(0, 5),
  vertical: b.vertical || 'general',
  client_id: b.client_id,
  tracking_duration_days: b.tracking_duration_days || 90,
  started_at: new Date().toISOString()
};
return [{ json: normalized }];

