// Aggregate all raw data into a single object for agent consumption.
const $n = (k) => $node[k]?.json ?? {};
const norm = $n['Validate & Normalize');
const serp = $n['DataForSEO SERP (primary kw)');
const vol = $n['DataForSEO KW Volume + CPC');
const blClient = $n['Client Backlink Profile');
const fc = $n['Firecrawl Full Site');
const psiMobile = $n['PageSpeed Insights (Mobile)');
const psiDesktop = $n['PageSpeed Insights (Desktop)');
const mf = $n['Mobile-Friendly Test');
const brain = $n['Query Client Brain (RAG)');

// Extract SERP features
const serpResult = serp?.tasks?.[0]?.result?.[0] ?? {};
const top10 = (serpResult.items || []).filter(i => i.type === 'organic').slice(0, 10);
const featuredSnippet = (serpResult.items || []).find(i => i.type === 'featured_snippet');
const peopleAlsoAsk = (serpResult.items || []).find(i => i.type === 'people_also_ask')?.items || [];
const aiOverview = (serpResult.items || []).find(i => i.type === 'ai_overview');
const localPack = (serpResult.items || []).find(i => i.type === 'local_pack');
const relatedSearches = serpResult.related_searches || [];

// Extract CWV
const cwvMobile = psiMobile?.lighthouseResult?.audits || {};
const lcp = cwvMobile['largest-contentful-paint']?.numericValue;
const inp = cwvMobile['interactive']?.numericValue; // proxy
const cls = cwvMobile['cumulative-layout-shift']?.numericValue;
const perfScore = psiMobile?.lighthouseResult?.categories?.performance?.score;
const seoScore = psiMobile?.lighthouseResult?.categories?.seo?.score;

// Extract crawl summary
const pages = fc?.data || [];
const schemaPages = pages.filter(p => (p.html || '').includes('application/ld+json'));
const missingTitle = pages.filter(p => !p.metadata?.title).length;
const missingMeta = pages.filter(p => !p.metadata?.description).length;

return [{ json: {
  ...norm,
  serp: {
    top10: top10.map(r => ({ rank: r.rank_absolute, url: r.url, title: r.title, description: r.description, domain: r.domain })),
    featured_snippet: featuredSnippet ? { source: featuredSnippet.url, text: featuredSnippet.description } : null,
    people_also_ask: peopleAlsoAsk.map(q => q.title).slice(0, 10),
    ai_overview_present: !!aiOverview,
    ai_overview_references: aiOverview?.references || [],
    local_pack_present: !!localPack,
    related_searches: relatedSearches.slice(0, 20)
  },
  keywords: (vol?.tasks?.[0]?.result || []).map(k => ({
    keyword: k.keyword, search_volume: k.search_volume, cpc: k.cpc, competition: k.competition_level
  })),
  backlinks_summary: {
    total: blClient?.tasks?.[0]?.result?.[0]?.backlinks ?? 0,
    referring_domains: blClient?.tasks?.[0]?.result?.[0]?.referring_domains ?? 0,
    rank: blClient?.tasks?.[0]?.result?.[0]?.rank ?? 0
  },
  technical: {
    pages_crawled: pages.length,
    pages_with_schema: schemaPages.length,
    pages_missing_title: missingTitle,
    pages_missing_meta_desc: missingMeta,
    lcp_ms: lcp,
    inp_ms: inp,
    cls: cls,
    perf_score: perfScore,
    seo_score: seoScore,
    mobile_friendly: mf?.mobileFriendliness === 'MOBILE_FRIENDLY'
  },
  homepage_html: pages.find(p => /^https?:\/\/[^/]+\/?$/.test(p.metadata?.sourceURL || ''))?.html || null,
  crawl_sample: pages.slice(0, 25).map(p => ({ url: p.metadata?.sourceURL, title: p.metadata?.title, description: p.metadata?.description })),
  client_brain: brain
} }];

