// Combine all 5 agent outputs into a single payload for the Orchestrator.
const parse = (v) => {
  if (!v) return null;
  if (typeof v === 'string') { try { return JSON.parse(v); } catch { return v; } }
  if (v.response) { try { return JSON.parse(v.response); } catch { return v.response; } }
  return v;
};
const base = $node['Aggregate Raw Data'].json;
return [{ json: {
  ...base,
  agent_outputs: {
    competitive_intelligence: parse($node['Agent: Competitive Intelligence'].json),
    content_strategy: parse($node['Agent: Content Strategy'].json),
    technical_seo: parse($node['Agent: Technical SEO'].json),
    geo_optimization: parse($node['Agent: GEO Optimization'].json),
    backlink_strategy: parse($node['Agent: Backlink Strategist'].json)
  }
} }];

